import math


def calculate_rectangle_properties(length, width):
    area = length * width
    perimeter = 2 * (length + width)
    diagonal = math.sqrt(length ** 2 + width ** 2)
    return {'area': area, 'perimeter': perimeter, 'diagonal': diagonal}

