from math import sqrt

def is_prime(n):
    if n <= 1:
        return False
    for i in range(2, int(sqrt(n)) + 1):
        if n % i == 0:
            return False
    return True

def find_largest_prime(numbers):
    largest_prime = -1
    for number in numbers:
        if is_prime(number) and number > largest_prime:
            largest_prime = number
    return largest_prime

